  if (!filename.empty()) {
    currentFileName = filename;
    lineOffset = lineNum - 1; // 行号偏移
  }
}

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  // 处理预处理行标记
  if (tokenTypeName == "LineAfterPreprocessing") {
    process_line_marker(token->getText());
    return; // 不输出预处理标记
  }

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // 计算位置信息
  int line = token->getLine();
  int column = token->getCharPositionInLine() + 1; // ANTLR 从0开始，clang从1开始

  // 调整行号：考虑预处理行标记的偏移
  int adjustedLine = line + lineOffset;

  std::string locInfo;
  if (tokenTypeName == "eof") {
    // EOF 的特殊处理：行号+1，列号1
    locInfo = " Loc=<" + currentFileName + ":" + std::to_string(adjustedLine + 1) + ":1>";
  } else {
    locInfo = " Loc=<" + currentFileName + ":" + std::to_string(adjustedLine) + ":" + std::to_string(column) + ">";
  }

  // 判断 StartOfLine 和 LeadingSpace
  bool startOfLine = (column == 1);
  bool leadingSpace = (column > 1); // 简化处理：如果列号>1，则认为前面有空格

  // 输出 token
  outFile << tokenTypeName << " '" << (token->getText() == "<EOF>" ? "" : token->getText()) << "'";

  // 输出标记
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << "\t [LeadingSpace]";

  // 输出位置信息
  outFile << "\t" << locInfo << std::endl;
}

